.wrap {
  width: 100%;
  max-width: 320px;
  margin: 0 auto;
  background: #fcd34d;
  padding: 10px;
  text-align: center;
}
img { max-width: 100%; }

.hero {
  height: 50vh; /* نصف ارتفاع النافذة للتجربة */
  background: linear-gradient(135deg, #6366f1, #06b6d4);
  color: white;
  display: flex;
  align-items: center;
  justify-content: center;
}
